#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    return *(int*)b - *(int*)a;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        long long totalSum = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &A[i]);
            totalSum += A[i];
        }
        qsort(A, N, sizeof(int), cmp_desc);
        long long pref = 0;
        long long best = 0;
        long long N1000 = (long long)N * 1000LL;
        for (int k = 0; k <= N; ++k) {
            long long attack = pref; // sum of largest k
            long long defense = (N - k) * 1000LL - (totalSum - attack);
            long long rating = attack * defense;
            if (rating > best) best = rating;
            if (k < N) pref += A[k];
        }
        printf("%lld\n", best);
        free(A);
    }
    return 0;
}

