import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] a = new int[N];
            long totalSum = 0;
            for (int i = 0; i < N; i++) {
                a[i] = fs.nextInt();
                totalSum += a[i];
            }
            Arrays.sort(a);
            // reverse to descending
            for (int i = 0; i < N / 2; i++) {
                int tmp = a[i];
                a[i] = a[N - 1 - i];
                a[N - 1 - i] = tmp;
            }
            long pref = 0, best = 0;
            for (int k = 0; k <= N; k++) {
                long attack = pref;
                long defense = (long) (N - k) * 1000L - (totalSum - attack);
                long rating = attack * defense;
                if (rating > best) best = rating;
                if (k < N) pref += a[k];
            }
            sb.append(best).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for Java
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

