  idx += N;
  let totalSum = 0;
  for (const v of A) totalSum += v;
  A.sort((a, b) => b - a);
  let pref = 0;
  let best = 0;
  for (let k = 0; k <= N; ++k) {
    const attack = pref;
    const defense = (N - k) * 1000 - (totalSum - attack);
    const rating = attack * defense;
    if (rating > best) best = rating;
    if (k < N) pref += A[k];
  }
  outputs.push(String(best));
}
